.left(IntBinaryTree.of(171).right(IntBinaryTree.of(51)))
.right(IntBinaryTree.of(19));
BinaryTreeNode root = IntBinaryTree.of(77, left, left);
assertEquals(
expected,
BinaryTreePrint.print(root));
